<?php

function processXMLConfiguration($xmlContent) {
    if (empty($xmlContent)) {
        return [
            'success' => false,
            'error' => 'Empty XML content provided',
            'settings' => []
        ];
    }

    libxml_use_internal_errors(true);
    libxml_disable_entity_loader(true);
    
    $xml = simplexml_load_string($xmlContent, 'SimpleXMLElement', LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR);
    
    if ($xml === false) {
        $errors = [];
        foreach (libxml_get_errors() as $error) {
            $errors[] = trim($error->message);
        }
        libxml_clear_errors();
        
        return [
            'success' => false,
            'error' => 'XML parsing failed: ' . implode(', ', $errors),
            'settings' => []
        ];
    }
    
    $settings = extractSettings($xml);
    
    return [
        'success' => true,
        'error' => null,
        'settings' => $settings
    ];
}

function extractSettings($xmlElement) {
    $settings = [];
    
    foreach ($xmlElement->attributes() as $key => $value) {
        $settings['@' . $key] = (string)$value;
    }
    
    if ($xmlElement->count() === 0) {
        $textContent = trim((string)$xmlElement);
        if (!empty($textContent)) {
            return $textContent;
        }
        return $settings ?: null;
    }
    
    $children = [];
    foreach ($xmlElement->children() as $child) {
        $childName = $child->getName();
        $childValue = extractSettings($child);
        
        if (isset($children[$childName])) {
            if (!is_array($children[$childName]) || !isset($children[$childName][0])) {
                $children[$childName] = [$children[$childName]];
            }
            $children[$childName][] = $childValue;
        } else {
            $children[$childName] = $childValue;
        }
    }
    
    if (!empty($children)) {
        $settings = array_merge($settings, $children);
    }
    
    return $settings;
}

function loadXMLConfigurationFromFile($filePath) {
    if (!file_exists($filePath)) {
        return [
            'success' => false,
            'error' => 'Configuration file not found',
            'settings' => []
        ];
    }
    
    if (!is_readable($filePath)) {
        return [
            'success' => false,
            'error' => 'Configuration file is not readable',
            'settings' => []
        ];
    }
    
    $maxFileSize = 10 * 1024 * 1024;
    if (filesize($filePath) > $maxFileSize) {
        return [
            'success' => false,
            'error' => 'Configuration file exceeds maximum size limit',
            'settings' => []
        ];
    }
    
    $xmlContent = file_get_contents($filePath);
    
    return processXMLConfiguration($xmlContent);
}

function validateXMLConfiguration($xmlContent, $requiredFields = []) {
    $result = processXMLConfiguration($xmlContent);
    
    if (!$result['success']) {
        return $result;
    }
    
    $settings = $result['settings'];
    $missingFields = [];
    
    foreach ($requiredFields as $field) {
        if (!isset($settings[$field])) {
            $missingFields[] = $field;
        }
    }
    
    if (!empty($missingFields)) {
        return [
            'success' => false,
            'error' => 'Missing required fields: ' . implode(', ', $missingFields),
            'settings' => $settings
        ];
    }
    
    return [
        'success' => true,
        'error' => null,
        'settings' => $settings
    ];
}

function getConfigurationValue($settings, $path, $default = null) {
    $keys = explode('.', $path);
    $current = $settings;
    
    foreach ($keys as $key) {
        if (is_array($current) && isset($current[$key])) {
            $current = $current[$key];
        } else {
            return $default;
        }
    }
    
    return $current;
}

function mergeXMLConfigurations($xmlContent1, $xmlContent2) {
    $result1 = processXMLConfiguration($xmlContent1);
    $result2 = processXMLConfiguration($xmlContent2);
    
    if (!$result1['success']) {
        return $result1;
    }
    
    if (!$result2['success']) {
        return $result2;
    }
    
    $mergedSettings = array_merge_recursive($result1['settings'], $result2['settings']);
    
    return [
        'success' => true,
        'error' => null,
        'settings' => $mergedSettings
    ];
}

function convertSettingsToArray($settings) {
    if (!is_array($settings)) {
        return $settings;
    }
    
    $result = [];
    foreach ($settings as $key => $value) {
        $result[$key] = convertSettingsToArray($value);
    }
    
    return $result;
}

function handleUploadedXMLFile($uploadedFile) {
    if (!isset($uploadedFile['tmp_name']) || !is_uploaded_file($uploadedFile['tmp_name'])) {
        return [
            'success' => false,
            'error' => 'Invalid uploaded file',
            'settings' => []
        ];
    }
    
    if ($uploadedFile['error'] !== UPLOAD_ERR_OK) {
        return [
            'success' => false,
            'error' => 'File upload error: ' . $uploadedFile['error'],
            'settings' => []
        ];
    }
    
    $allowedExtensions = ['xml'];
    $fileExtension = strtolower(pathinfo($uploadedFile['name'], PATHINFO_EXTENSION));
    
    if (!in_array($fileExtension, $allowedExtensions)) {
        return [
            'success' => false,
            'error' => 'Invalid file extension. Only XML files are allowed',
            'settings' => []
        ];
    }
    
    return loadXMLConfigurationFromFile($uploadedFile['tmp_name']);
}

function sanitizeXMLInput($xmlContent) {
    $xmlContent = preg_replace('/<!DOCTYPE[^>]*>/i', '', $xmlContent);
    $xmlContent = preg_replace('/<!ENTITY[^>]*>/i', '', $xmlContent);
    
    return $xmlContent;
}

function processSecureXMLConfiguration($xmlContent) {
    $sanitized = sanitizeXMLInput($xmlContent);
    return processXMLConfiguration($sanitized);
}

